import os
import json
import logging
from azure.storage.blob import BlobServiceClient
from azure.functions import HttpRequest, HttpResponse

# Initialize BlobServiceClient
connection_string = os.getenv("AZURE_STORAGE_CONNECTION_STRING")
blob_service_client = BlobServiceClient.from_connection_string(connection_string)

def main(req: HttpRequest) -> HttpResponse:
    logging.info('HTTP trigger function processed a request.')

    # Validate query parameter
    blob_path = req.params.get('blob_path')
    if not blob_path or not isinstance(blob_path, str):
        return HttpResponse("Invalid blob path", status_code=400)

    # Prevent directory traversal attacks
    if '..' in blob_path or blob_path.startswith('/'):
        return HttpResponse("Invalid blob path", status_code=400)

    try:
        # Get the container name and blob name
        container_name, blob_name = blob_path.split('/', 1)
        
        # Get the blob client
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)

        # Read the blob content
        blob_data = blob_client.download_blob().readall()

        return HttpResponse(blob_data, mimetype="application/octet-stream", status_code=200)
    
    except Exception as e:
        logging.error(f"Error reading blob: {str(e)}")
        return HttpResponse("Error reading blob", status_code=500)